svg.script:
//!export-start
let _pb_value = false;

let _pc_colorOn = '#00c853';
let _pc_colorOff = '#d50000';

let _pc_backgroundOn = '#00ff00';
let _pc_backgroundOff = '#333333';
let _pn_backgroundThickness = 0;

let _ps_textOn = 'ON';
let _ps_textOff = 'OFF';
let _ps_fontFamily = 'Arial';
let _pn_fontSize = 15;
let _ps_textAlign = 'center';
let _pn_cornerRadius = 0;
//!export-end

let currentValue = false;

const body = document.getElementById('btnBody');
const bg = document.getElementById('btnBackground');
const text = document.getElementById('btnText');
const symbol = document.getElementById('fuxaSymbol');

// ================= RECEIVE FROM FUXA =================
function putValue(id, value) {

  if (id === '_pb_value')
    currentValue = (value === true || value === 1 || value === '1');

  if (id === '_pc_colorOn') _pc_colorOn = value;
  if (id === '_pc_colorOff') _pc_colorOff = value;
  if (id === '_pc_backgroundOn') _pc_backgroundOn = value;
  if (id === '_pc_backgroundOff') _pc_backgroundOff = value;
  if (id === '_pn_backgroundThickness') _pn_backgroundThickness = value;
  if (id === '_ps_textOn') _ps_textOn = value;
  if (id === '_ps_textOff') _ps_textOff = value;
  if (id === '_ps_fontFamily') _ps_fontFamily = value;
  if (id === '_pn_fontSize') _pn_fontSize = value;
  if (id === '_ps_textAlign') _ps_textAlign = value;
  if (id === '_pn_cornerRadius') _pn_cornerRadius = value;

  updateVisual();
}

// ================= SEND TO FUXA =================
function postValue(id, value) {
  if (window.parent && window.parent.postValue) {
    window.parent.postValue(id, value);
  }
}

// ================= UPDATE VISUAL =================
function updateVisual() {

  bg.setAttribute('fill', currentValue ? _pc_backgroundOn : _pc_backgroundOff);
  body.setAttribute('fill', currentValue ? _pc_colorOn : _pc_colorOff);

  let thickness = Math.max(0, _pn_backgroundThickness);

  body.setAttribute('x', thickness);
  body.setAttribute('y', thickness);
  body.setAttribute('width', 100 - (thickness * 2));
  body.setAttribute('height', 50 - (thickness * 2));

  text.textContent = currentValue ? _ps_textOn : _ps_textOff;
  text.setAttribute('font-family', _ps_fontFamily);
  text.setAttribute('font-size', _pn_fontSize);

  if (_ps_textAlign === 'left') {
    text.setAttribute('text-anchor', 'start');
    text.setAttribute('x', 5);
  } else if (_ps_textAlign === 'right') {
    text.setAttribute('text-anchor', 'end');
    text.setAttribute('x', 95);
  } else {
    text.setAttribute('text-anchor', 'middle');
    text.setAttribute('x', 50);
  }

  let r = Math.max(0, _pn_cornerRadius);
  bg.setAttribute('rx', r);
  bg.setAttribute('ry', r);
  body.setAttribute('rx', r);
  body.setAttribute('ry', r);
}

// ================= MOMENTARY =================
symbol.addEventListener('mousedown', function() {
  currentValue = true;
  updateVisual();
  postValue('_pb_value', true);
});

symbol.addEventListener('mouseup', function() {
  currentValue = false;
  updateVisual();
  postValue('_pb_value', false);
});

symbol.addEventListener('mouseleave', function() {
  currentValue = false;
  updateVisual();
  postValue('_pb_value', false);
});

symbol.addEventListener('touchstart', function() {
  currentValue = true;
  updateVisual();
  postValue('_pb_value', true);
});

symbol.addEventListener('touchend', function() {
  currentValue = false;
  updateVisual();
  postValue('_pb_value', false);
});

updateVisual();
